sql:
SELECT name, permissions
FROM memory_regions
WHERE active = 1 AND region_type = 'heap' AND size > 1024;

SELECT region_type
FROM memory_regions
WHERE region_id = 1;

SELECT COUNT(*) AS Total_Memory_Regions
FROM memory_regions
WHERE size > 10000;

external_knowledge:
- 'Last spring month' refers to April 2023;
- 'Heap memory regions' are memory regions specifically of type 'heap';
- 'Engineers' are users with the role 'engineer';
- 'Written to' means the access type 'write'.

sql:
SELECT usage_id, usage 
FROM memory_usage 
WHERE usage > 50;

SELECT COUNT(DISTINCT region_id)
FROM access_logs
WHERE access_type = 'write';

SELECT *
FROM security_threats
WHERE status = 'open';

external_knowledge:
- 'vibrant regions' metaphorically refers to active memory regions;
- 'currently awake' indicates that the regions are active (`mr.active = 1`);
- 'digital landscape' is a metaphor for the database;
- 'keys that unlock their doors' metaphorically represents the permissions associated with each memory region.

sql:
SELECT mr.name AS 'Region Name', ac.description AS 'Access Control'
FROM memory_regions mr
INNER JOIN access_control ac ON mr.region_id = ac.region_id;

SELECT region_id, MAX(usage) AS highest_usage
FROM memory_usage
GROUP BY region_id;
